 74→    private fun PostPrepublishingHomeFragmentBinding.setupRecyclerView() {
 75→        val adapter = PrepublishingHomeAdapter(requireActivity())
 76→        // use WrappingLinearLayoutManager to properly handle recycler with wrap_content height
 77→        val layoutManager = WrappingLinearLayoutManager(
 78→            requireContext(),
 79→            LinearLayoutManager.VERTICAL,
 80→            false
 81→        )
 82→
 83→        adapter.registerAdapterDataObserver(
 84→            object : RecyclerView.AdapterDataObserver() {
 85→                override fun onItemRangeRemoved(positionStart: Int, itemCount: Int) {
 86→                    layoutManager.onItemRangeRemoved()
 87→                }
 88→            }
 89→        )
 90→
 91→        // since the recycler is anchored at the bottom, this is needed so the animation shrinks the item from the top
 92→        layoutManager.stackFromEnd = true
 93→
 94→        actionsRecyclerView.layoutManager = layoutManager
 95→        actionsRecyclerView.adapter = adapter
 96→        actionsRecyclerView.isNestedScrollingEnabled = false
 97→    }
 98→
 99→    private fun PostPrepublishingHomeFragmentBinding.initViewModel() {
100→        viewModel = ViewModelProvider(this@PrepublishingHomeFragment, viewModelFactory)
101→            .get(PrepublishingHomeViewModel::class.java)
102→
103→        viewModel.storyTitleUiState.observe(viewLifecycleOwner) { storyTitleUiState ->
104→            uiHelpers.updateVisibility(storyTitleHeaderView, true)
105→            storyTitleHeaderView.init(uiHelpers, imageManager, storyTitleUiState)
106→        }
107→
108→        viewModel.uiState.observe(viewLifecycleOwner) { uiState ->
109→            uiState?.let { (actionsRecyclerView.adapter as PrepublishingHomeAdapter).update(it) }
110→        }
111→
112→        viewModel.onActionClicked.observeEvent(viewLifecycleOwner) { actionType ->
113→            actionClickedListener?.onActionClicked(actionType)
114→        }
115→
116→        viewModel.onSubmitButtonClicked.observeEvent(viewLifecycleOwner) { publishPost ->
117→            actionClickedListener?.onSubmitButtonClicked(publishPost)
118→        }
119→
120→        val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
121→            "arguments can't be null."
122→        }
123→
124→        viewModel.start(getEditPostRepository(), getSite(), isStoryPost)
125→    }
126→
127→    private fun setupJetpackSocialViewModel() {
128→        jetpackSocialViewModel = (parentFragment as PrepublishingSocialViewModelProvider)
129→            .getEditorJetpackSocialViewModel()
130→
131→        merge(
132→            jetpackSocialViewModel.jetpackSocialUiState,
133→            jetpackSocialViewModel.jetpackSocialContainerVisibility
134→        ) { uiState, visibility ->
135→            Pair(uiState, visibility)
136→        }.observe(viewLifecycleOwner) { pair ->
137→            val uiState = pair.first ?: return@observe
138→            val visibility = pair.second ?: return@observe
139→            viewModel.updateJetpackSocialState(uiState.takeIf { visibility.showInPrepublishingSheet })
140→        }
141→    }
142→
143→    private fun getSite(): SiteModel {
144→        val editPostActivityHook = requireNotNull(getEditPostActivityHook()) {
145→            "EditPostActivityHook shouldn't be null."
146→        }
147→
148→        return editPostActivityHook.site
149→    }
150→
151→    private fun getEditPostRepository(): EditPostRepository {
152→        val editPostActivityHook = requireNotNull(getEditPostActivityHook()) {
153→            "This is possibly null because it's " +
154→                    "called during config changes."
155→        }
156→
157→        return editPostActivityHook.editPostRepository
158→    }
159→
160→    private fun getEditPostActivityHook(): EditPostSettingsFragment.EditPostActivityHook? {
161→        val activity = activity ?: return null
162→        return if (activity is EditPostSettingsFragment.EditPostActivityHook) {
163→            activity
164→        } else {
165→            throw RuntimeException("$activity must implement EditPostActivityHook")
166→        }
167→    }
168→
169→    companion object {
170→        const val TAG = "prepublishing_home_fragment_tag"
171→        const val IS_STORY_POST = "prepublishing_home_fragment_is_story_post"
172→
173→        fun newInstance(isStoryPost: Boolean) =
174→            PrepublishingHomeFragment().apply {
175→                arguments = Bundle().apply {
176→                    putBoolean(IS_STORY_POST, isStoryPost)
177→                }
178→            }
179→    }
180→}
